import xml.etree.ElementTree as ET
from saml import validate_response

def validate_saml_response(xml):
    # Parse the XML response using python3-saml or lxml
    root = ET.fromstring(xml)

    # Validate the signature exists and is valid
    if not validate_response(root):
        raise ValueError("Invalid SAML response")

    # Extract assertions and authenticate users
    for assertion in root.findall(".//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion"):
        user = assertion.attrib["Subject"].split(" ")[1]
        print(f"Authenticated user {user}")